import csv
from collections import defaultdict
d=defaultdict(list)
with open('disease_relevant_inhibited_all_normalized_ode/repeat_variability_analysis_20260704_2021/average_curves_by_setting.csv') as f:
    r=csv.DictReader(f)
    for row in r:
        d[row['setting']].append((float(row['time']),float(row['mean_y'])))
def cross(pts,frac):
    ym=max(p[1] for p in pts)
    thr=frac*ym
    for t,y in pts:
        if y>=thr: return round(t,3)
    return None
# unseeded m0:3e-6 varying cd
ks=[k for k in d if 'M0:0_P0:0' in k and 'm0:3e-6' in k]
for k in sorted(ks):
    pts=sorted(d[k])
    print(k.split('_')[2], 't10',cross(pts,.1),'t50',cross(pts,.5),'t90',cross(pts,.9))
